#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define NX 4096
#define NY 4096
#define STEPS 1000

int main() {
    float *A = (float*)malloc(NX * NY * sizeof(float));
    float *Anew = (float*)malloc(NX * NY * sizeof(float));

    // Initialize arrays
    #pragma omp parallel for collapse(2)
    for (int j = 0; j < NY; j++) {
        for (int i = 0; i < NX; i++) {
            A[j * NX + i] = 0.0f;
            Anew[j * NX + i] = 0.0f;
        }
    }

    // Set boundary conditions
    #pragma omp parallel for
    for (int i = 0; i < NX; i++) {
        A[i] = 1.0f;
        Anew[i] = 1.0f;
    }

    for (int j = 0; j < NY; j++) {
        A[j * NX] = 1.0f;
        Anew[j * NX] = 1.0f;
    }

    // Time stepping
    for (int t = 0; t < STEPS; t++) {
        #pragma omp parallel for collapse(2)
        for (int j = 1; j < NY - 1; j++) {
            for (int i = 1; i < NX - 1; i++) {
                Anew[j * NX + i] = 0.25f * (A[j * NX + (i + 1)] + A[j * NX + (i - 1)] +
                                           A[(j - 1) * NX + i] + A[(j + 1) * NX + i]);
            }
        }

        // Swap pointers
        float *tmp = A;
        A = Anew;
        Anew = tmp;
    }

    // Print final result for verification
    printf("A[0] = %f\n", A[0]);
    printf("A[NX*NY/2] = %f\n", A[(NX * NY) / 2]);
    printf("A[NX*NY-1] = %f\n", A[NX * NY - 1]);

    free(A);
    free(Anew);

    return 0;
}
